280→        }
281→    }
282→
283→    fun onPasswordPromptResult(result: PasswordPromptResult) {
284→        updateUiModel {
285→            val index = getListIndexOfAccount(result.accountUuid)
286→            setSettingsListState(index, ImportStatus.IMPORT_SUCCESS)
287→
288→            updateCloseButtonAndImportStatusText()
289→        }
290→
291→        viewModelScope.launch(backgroundDispatcher) {
292→            withContext(NonCancellable) {
293→                with(result) {
294→                    accountActivator.enableAccount(accountUuid, incomingServerPassword, outgoingServerPassword)
295→                }
296→            }
297→        }
298→    }
299→
300→    fun onReturnAfterAuthorization() {
301→        currentlyAuthorizingAccountUuid?.let { accountUuid ->
302→            currentlyAuthorizingAccountUuid = null
303→            updateUiModel {
304→                val index = getListIndexOfAccount(accountUuid)
305→                setSettingsListState(index, ImportStatus.IMPORT_SUCCESS)
306→                updateCloseButtonAndImportStatusText()
307→            }
308→
309→            viewModelScope.launch(backgroundDispatcher) {
310→                withContext(NonCancellable) {
311→                    accountActivator.enableAccount(accountUuid)
312→                }
313→            }
314→        }
315→    }
