323→    private fun startReadSettingsFile(contentUri: Uri) {
324→        this.contentUri = contentUri
325→
326→        viewModelScope.launch {
327→            try {
328→                val (elapsed, contents) = measureRealtimeMillisWithResult {
329→                    withContext(backgroundDispatcher) {
330→                        readSettings(contentUri)
331→                    }
332→                }
333→
334→                if (elapsed < MIN_PROGRESS_DURATION) {
335→                    delay(MIN_PROGRESS_DURATION - elapsed)
336→                }
337→
338→                accountsMap = contents.accounts
339→                    .asSequence()
340→                    .mapIndexed { index, account -> index to account.uuid }
341→                    .toMap(mutableMapOf())
342→
343→                val items = mutableListOf<SettingsListItem>()
344→                if (contents.globalSettings) {
345→                    items.add(SettingsListItem.GeneralSettings())
346→                }
347→                contents.accounts.mapIndexedTo(items) { index, accountDescription ->
348→                    SettingsListItem.Account(index, accountDescription.name)
349→                }
350→
351→                updateUiModel {
352→                    initializeSettingsList(items)
353→                }
354→            } catch (e: Exception) {
355→                Timber.e(e, "Error reading settings file")
356→
357→                updateUiModel {
358→                    showReadFailureText()
359→                }
360→            }
361→        }
362→    }
363→
364→    private fun startImportSettings() {
365→        val contentUri = this.contentUri ?: error("contentUri is missing")
366→        viewModelScope.launch {
367→            try {
368→                val containsGeneralSettings = this@SettingsImportViewModel.containsGeneralSettings
369→                val importGeneralSettings = containsGeneralSettings && includeGeneralSettings
370→                val importAccounts = selectedAccounts.toList()
371→
372→                val (elapsed, importResults) = measureRealtimeMillisWithResult {
373→                    withContext(backgroundDispatcher) {
374→                        importSettings(contentUri, importGeneralSettings, importAccounts)
375→                    }
376→                }
377→
378→                if (elapsed < MIN_PROGRESS_DURATION) {
379→                    delay(MIN_PROGRESS_DURATION - elapsed)
380→                }
381→
382→                updateUiModel {
383→                    if (containsGeneralSettings) {
384→                        setGeneralSettingsImportStatus(importResults, importGeneralSettings)
385→                    }
386→                    setAccountsImportStatus(importResults)
387→
388→                    updateCloseButtonAndImportStatusText()
389→                }
390→            } catch (e: Exception) {
391→                Timber.e(e, "Error importing settings")
392→
393→                updateUiModel {
394→                    showImportErrorText()
395→                }
396→            }
397→        }
398→    }
