502→    private fun createSavedAccountList(): ArrayList<SavedAccountState> {
503→        return uiModel.settingsList
504→            .asSequence()
505→            .filterIsInstance<SettingsListItem.Account>()
506→            .map { accountItem ->
507→                val accountIndex = accountItem.accountIndex
508→                val accountState = accountStateMap[accountIndex]
509→                SavedAccountState(
510→                    accountIndex = accountIndex,
511→                    displayName = accountItem.displayName,
512→                    accountUuid = accountsMap[accountIndex]!!,
513→                    selected = accountItem.selected,
514→                    importStatus = accountItem.importStatus,
515→                    incomingServerName = accountState?.incomingServerName,
516→                    outgoingServerName = accountState?.outgoingServerName,
517→                    incomingServerPasswordNeeded = accountState?.incomingServerPasswordNeeded ?: false,
518→                    outgoingServerPasswordNeeded = accountState?.outgoingServerPasswordNeeded ?: false,
519→                )
520→            }
521→            .toCollection(ArrayList(uiModel.settingsList.size - 1))
522→    }
