  1→package com.fsck.k9.mailstore
  2→
  3→import app.k9mail.core.common.mail.Protocols
  4→import app.k9mail.core.mail.folder.api.FolderType
  5→import app.k9mail.legacy.account.Account
  6→import app.k9mail.legacy.account.Account.SpecialFolderSelection
  7→import app.k9mail.legacy.folder.RemoteFolder
  8→import app.k9mail.legacy.mailstore.FolderRepository
  9→import com.fsck.k9.Preferences
 10→
 11→/**
 12→ * Updates special folders in [Account] if they are marked as [SpecialFolderSelection.AUTOMATIC] or if they are marked
 13→ * as [SpecialFolderSelection.MANUAL] but have been deleted from the server.
 14→ */
 15→// TODO: Find a better way to deal with local-only special folders
 16→class SpecialFolderUpdater(
 17→    private val preferences: Preferences,
 18→    private val folderRepository: FolderRepository,
 19→    private val specialFolderSelectionStrategy: SpecialFolderSelectionStrategy,
 20→    private val account: Account,
 21→) {
 22→    fun updateSpecialFolders() {
 23→        val folders = folderRepository.getRemoteFolders(account)
 24→
 25→        updateInbox(folders)
 26→
 27→        if (!account.isPop3()) {
 28→            updateSpecialFolder(FolderType.ARCHIVE, folders)
 29→            updateSpecialFolder(FolderType.DRAFTS, folders)
 30→            updateSpecialFolder(FolderType.SENT, folders)
 31→            updateSpecialFolder(FolderType.SPAM, folders)
 32→            updateSpecialFolder(FolderType.TRASH, folders)
 33→        }
 34→
 35→        removeImportedSpecialFoldersData()
 36→        saveAccount()
 37→    }
 38→
 39→    private fun updateInbox(folders: List<RemoteFolder>) {
 40→        val oldInboxId = account.inboxFolderId
 41→        val newInboxId = folders.firstOrNull { it.type == FolderType.INBOX }?.id
 42→        if (newInboxId == oldInboxId) return
 43→
 44→        account.inboxFolderId = newInboxId
 45→
 46→        if (oldInboxId != null && folders.any { it.id == oldInboxId }) {
 47→            folderRepository.setIncludeInUnifiedInbox(account, oldInboxId, false)
 48→        }
 49→
 50→        if (newInboxId != null) {
 51→            folderRepository.setIncludeInUnifiedInbox(account, newInboxId, true)
 52→            folderRepository.setVisible(account, newInboxId, true)
 53→            folderRepository.setSyncEnabled(account, newInboxId, true)
 54→            folderRepository.setNotificationsEnabled(account, newInboxId, true)
 55→        }
 56→    }
 57→
 58→    private fun updateSpecialFolder(type: FolderType, folders: List<RemoteFolder>) {
 59→        val importedServerId = getImportedSpecialFolderServerId(type)
 60→        if (importedServerId != null) {
 61→            val folderId = folders.firstOrNull { it.serverId == importedServerId }?.id
 62→            if (folderId != null) {
 63→                setSpecialFolder(type, folderId, getSpecialFolderSelection(type))
 64→                return
 65→            }
 66→        }
 67→
 68→        when (getSpecialFolderSelection(type)) {
 69→            SpecialFolderSelection.AUTOMATIC -> {
 70→                val specialFolder = specialFolderSelectionStrategy.selectSpecialFolder(folders, type)
 71→                setSpecialFolder(type, specialFolder?.id, SpecialFolderSelection.AUTOMATIC)
 72→            }
 73→            SpecialFolderSelection.MANUAL -> {
 74→                if (folders.none { it.id == getSpecialFolderId(type) }) {
 75→                    setSpecialFolder(type, null, SpecialFolderSelection.MANUAL)
 76→                }
 77→            }
 78→        }
 79→    }
 80→
 81→    private fun getSpecialFolderSelection(type: FolderType) = when (type) {
 82→        FolderType.ARCHIVE -> account.archiveFolderSelection
 83→        FolderType.DRAFTS -> account.draftsFolderSelection
 84→        FolderType.SENT -> account.sentFolderSelection
 85→        FolderType.SPAM -> account.spamFolderSelection
 86→        FolderType.TRASH -> account.trashFolderSelection
 87→        else -> throw AssertionError("Unsupported: $type")
 88→    }
 89→
 90→    private fun getSpecialFolderId(type: FolderType): Long? = when (type) {
 91→        FolderType.ARCHIVE -> account.archiveFolderId
 92→        FolderType.DRAFTS -> account.draftsFolderId
 93→        FolderType.SENT -> account.sentFolderId
 94→        FolderType.SPAM -> account.spamFolderId
 95→        FolderType.TRASH -> account.trashFolderId
 96→        else -> throw AssertionError("Unsupported: $type")
 97→    }
 98→
 99→    private fun getImportedSpecialFolderServerId(type: FolderType): String? = when (type) {
100→        FolderType.ARCHIVE -> account.importedArchiveFolder
101→        FolderType.DRAFTS -> account.importedDraftsFolder
102→        FolderType.SENT -> account.importedSentFolder
103→        FolderType.SPAM -> account.importedSpamFolder
104→        FolderType.TRASH -> account.importedTrashFolder
105→        else -> throw AssertionError("Unsupported: $type")
106→    }
107→
108→    private fun setSpecialFolder(type: FolderType, folderId: Long?, selection: SpecialFolderSelection) {
109→        if (getSpecialFolderId(type) == folderId) return
110→
111→        when (type) {
112→            FolderType.ARCHIVE -> account.setArchiveFolderId(folderId, selection)
113→            FolderType.DRAFTS -> account.setDraftsFolderId(folderId, selection)
114→            FolderType.SENT -> account.setSentFolderId(folderId, selection)
115→            FolderType.SPAM -> account.setSpamFolderId(folderId, selection)
116→            FolderType.TRASH -> account.setTrashFolderId(folderId, selection)
117→            else -> throw AssertionError("Unsupported: $type")
118→        }
119→
120→        if (folderId != null) {
121→            folderRepository.setVisible(account, folderId, true)
122→        }
123→    }
124→
125→    private fun removeImportedSpecialFoldersData() {
126→        account.importedArchiveFolder = null
127→        account.importedDraftsFolder = null
128→        account.importedSentFolder = null
129→        account.importedSpamFolder = null
130→        account.importedTrashFolder = null
131→    }
132→
133→    private fun saveAccount() {
134→        preferences.saveAccount(account)
135→    }
136→
137→    private fun Account.isPop3() = incomingServerSettings.type == Protocols.POP3
138→}
