183→            outState.putEnum(STATE_STATUS_TEXT, statusText)
184→            outState.putString(STATE_CURRENTLY_AUTHORIZING_ACCOUNT_UUID, currentlyAuthorizingAccountUuid)
185→
186→            if (hasDocumentBeenRead) {
187→                val containsGeneralSettings = this@SettingsImportViewModel.containsGeneralSettings
188→                outState.putBoolean(STATE_CONTAINS_GENERAL_SETTINGS, containsGeneralSettings)
189→                if (containsGeneralSettings) {
190→                    outState.putBoolean(STATE_INCLUDE_GENERAL_SETTINGS, includeGeneralSettings)
191→                    outState.putEnum(STATE_GENERAL_SETTINGS_IMPORT_STATUS, generalSettingsImportStatus)
192→                }
193→                outState.putParcelableArrayList(STATE_ACCOUNT_LIST, createSavedAccountList())
