400→    private fun SettingsImportUiModel.setGeneralSettingsImportStatus(
401→        importResults: ImportResults,
402→        importGeneralSettings: Boolean,
403→    ) {
404→        val importStatus = when {
405→            importResults.globalSettings -> ImportStatus.IMPORT_SUCCESS
406→            importGeneralSettings -> ImportStatus.IMPORT_FAILURE
407→            else -> ImportStatus.NOT_SELECTED
408→        }
409→        setSettingsListState(0, importStatus)
410→    }
411→
412→    private fun SettingsImportUiModel.setAccountsImportStatus(importResults: ImportResults) {
413→        val failedToImport = importResults.erroneousAccounts.map { it.uuid }.toHashSet()
414→        settingsList.forEachIndexed { index, listItem ->
415→            if (listItem !is SettingsListItem.Account) return@forEachIndexed
416→
417→            val accountIndex = listItem.accountIndex
418→            val accountUuid = accountsMap[accountIndex]
419→
420→            if (accountUuid in failedToImport) {
421→                setSettingsListState(index, ImportStatus.IMPORT_FAILURE)
422→            } else {
423→                val accountPair = importResults.importedAccounts.firstOrNull { it.original.uuid == accountUuid }
424→                if (accountPair != null) {
425→                    accountsMap[accountIndex] = accountPair.imported.uuid
426→                    listItem.displayName = accountPair.imported.name
427→
428→                    if (accountPair.authorizationNeeded) {
429→                        setSettingsListState(index, ImportStatus.IMPORT_SUCCESS_AUTHORIZATION_REQUIRED)
430→                    } else if (accountPair.incomingPasswordNeeded || accountPair.outgoingPasswordNeeded) {
431→                        accountStateMap[accountIndex] = AccountState(
432→                            accountPair.incomingServerName,
433→                            accountPair.outgoingServerName,
434→                            accountPair.incomingPasswordNeeded,
435→                            accountPair.outgoingPasswordNeeded,
436→                        )
437→
438→                        setSettingsListState(index, ImportStatus.IMPORT_SUCCESS_PASSWORD_REQUIRED)
439→                    } else {
440→                        setSettingsListState(index, ImportStatus.IMPORT_SUCCESS)
441→                    }
442→                } else {
443→                    setSettingsListState(index, ImportStatus.NOT_SELECTED)
444→                }
445→            }
446→        }
447→    }
