252→            REQUEST_PICK_DOCUMENT -> handlePickDocumentResult(resultCode, data)
253→            REQUEST_PASSWORD_PROMPT -> handlePasswordPromptResult(resultCode, data)
254→            REQUEST_AUTHORIZATION -> handleAuthorizationResult(resultCode)
255→        }
256→    }
257→
258→    private fun handlePickDocumentResult(resultCode: Int, data: Intent?) {
259→        val contentUri = data?.data
260→        if (resultCode == Activity.RESULT_OK && contentUri != null) {
261→            viewModel.onDocumentPicked(contentUri)
262→        } else {
263→            viewModel.onDocumentPickCanceled()
264→        }
265→    }
266→
267→    private fun handlePasswordPromptResult(resultCode: Int, data: Intent?) {
268→        if (resultCode == Activity.RESULT_OK) {
269→            val resultIntent = data ?: error("No result intent received")
270→            val result = PasswordPromptResult.fromIntent(resultIntent)
271→            viewModel.onPasswordPromptResult(result)
272→        }
273→    }
274→
275→    private fun handleAuthorizationResult(resultCode: Int) {
276→        if (resultCode == Activity.RESULT_OK) {
277→            viewModel.onReturnAfterAuthorization()
278→        }
279→    }
280→
281→    private fun setFragmentResult(accountImported: Boolean) {
282→        setFragmentResult(
283→            requestKey = FRAGMENT_RESULT_KEY,
284→            result = bundleOf(
285→                FRAGMENT_RESULT_ACCOUNT_IMPORTED to accountImported,
286→            ),
287→        )
288→    }
289→
290→    companion object {
291→        private const val REQUEST_PICK_DOCUMENT = Activity.RESULT_FIRST_USER
292→        private const val REQUEST_PASSWORD_PROMPT = Activity.RESULT_FIRST_USER + 1
293→        private const val REQUEST_AUTHORIZATION = Activity.RESULT_FIRST_USER + 2
294→
295→        const val FRAGMENT_RESULT_KEY = "settings_import"
296→        const val FRAGMENT_RESULT_ACCOUNT_IMPORTED = "accountImported"
297→    }
298→}
