 1→package com.fsck.k9.mailstore
 2→
 3→import app.k9mail.legacy.account.Account
 4→import app.k9mail.legacy.mailstore.FolderRepository
 5→import com.fsck.k9.Preferences
 6→
 7→/**
 8→ * Update an Account's auto-expand folder after the folder list has been refreshed.
 9→ */
10→class AutoExpandFolderBackendFoldersRefreshListener(
11→    private val preferences: Preferences,
12→    private val account: Account,
13→    private val folderRepository: FolderRepository,
14→) : BackendFoldersRefreshListener {
15→    private var isFirstSync = false
16→
17→    override fun onBeforeFolderListRefresh() {
18→        isFirstSync = account.inboxFolderId == null
19→    }
20→
21→    override fun onAfterFolderListRefresh() {
22→        checkAutoExpandFolder()
23→
24→        removeImportedAutoExpandFolder()
25→        saveAccount()
26→    }
27→
28→    private fun checkAutoExpandFolder() {
29→        account.importedAutoExpandFolder?.let { folderName ->
30→            if (folderName.isEmpty()) {
31→                account.autoExpandFolderId = null
32→            } else {
33→                val folderId = folderRepository.getFolderId(account, folderName)
34→                account.autoExpandFolderId = folderId
35→            }
36→            return
37→        }
38→
39→        account.autoExpandFolderId?.let { autoExpandFolderId ->
40→            if (!folderRepository.isFolderPresent(account, autoExpandFolderId)) {
41→                account.autoExpandFolderId = null
42→            }
43→        }
44→
45→        if (isFirstSync && account.autoExpandFolderId == null) {
46→            account.autoExpandFolderId = account.inboxFolderId
47→        }
48→    }
49→
50→    private fun removeImportedAutoExpandFolder() {
51→        account.importedAutoExpandFolder = null
52→    }
53→
54→    private fun saveAccount() {
55→        preferences.saveAccount(account)
56→    }
57→}
