 5→internal class AccountSettingsValidator {
 6→    private val identitySettingsValidator = IdentitySettingsValidator()
 7→    private val folderSettingsValidator = FolderSettingsValidator()
 8→    private val serverSettingsValidator = ServerSettingsValidator()
 9→
10→    fun validate(contentVersion: Int, account: SettingsFile.Account): ValidatedSettings.Account {
11→        val validatedSettings = AccountSettingsDescriptions.validate(contentVersion, account.settings.orEmpty(), true)
12→
13→        val incomingServer = validateIncomingServer(contentVersion, account.incoming)
14→        val outgoingServer = validateOutgoingServer(contentVersion, account.outgoing)
15→
16→        return ValidatedSettings.Account(
17→            uuid = account.uuid,
18→            name = account.name,
19→            incoming = incomingServer,
20→            outgoing = outgoingServer,
21→            settings = validatedSettings,
22→            identities = validateIdentities(contentVersion, account.identities),
23→            folders = validateFolders(contentVersion, account.folders),
24→        )
25→    }
26→
27→    private fun validateIdentities(
28→        contentVersion: Int,
29→        identities: List<SettingsFile.Identity>?,
30→    ): List<ValidatedSettings.Identity> {
31→        if (identities.isNullOrEmpty()) {
32→            throw InvalidSettingValueException("Missing identities, there should be at least one.")
33→        }
34→
35→        return identities.map { identity ->
36→            identitySettingsValidator.validate(contentVersion, identity)
37→        }
38→    }
39→
40→    private fun validateFolders(
41→        contentVersion: Int,
42→        folders: List<SettingsFile.Folder>?,
43→    ): List<ValidatedSettings.Folder> {
44→        return folders.orEmpty()
45→            .map { folder ->
46→                folderSettingsValidator.validate(contentVersion, folder)
47→            }
48→    }
49→
50→    private fun validateIncomingServer(contentVersion: Int, incoming: SettingsFile.Server?): ValidatedSettings.Server {
51→        if (incoming == null) {
52→            throw InvalidSettingValueException("Missing incoming server settings")
53→        }
54→
55→        return serverSettingsValidator.validate(contentVersion, incoming)
56→    }
57→
58→    private fun validateOutgoingServer(contentVersion: Int, outgoing: SettingsFile.Server?): ValidatedSettings.Server {
59→        if (outgoing == null) {
60→            throw InvalidSettingValueException("Missing outgoing server settings")
61→        }
62→
63→        return serverSettingsValidator.validate(contentVersion, outgoing)
64→    }
65→}
