12→    private val imapStore: ImapStore,
13→) {
14→    fun refreshFolderList() {
15→        // TODO: Start using the proper server ID.
16→        //  For now we still use the old server ID format (decoded, with prefix removed).
17→        val foldersOnServer = imapStore.getFolders().toLegacyFolderList()
18→        val oldFolderServerIds = backendStorage.getFolderServerIds()
19→
20→        backendStorage.updateFolders {
21→            val foldersToCreate = mutableListOf<FolderInfo>()
22→            for (folder in foldersOnServer) {
23→                if (folder.serverId !in oldFolderServerIds) {
24→                    foldersToCreate.add(FolderInfo(folder.serverId, folder.name, folder.type))
25→                } else {
26→                    changeFolder(folder.serverId, folder.name, folder.type)
27→                }
28→            }
29→            createFolders(foldersToCreate)
30→
31→            val newFolderServerIds = foldersOnServer.map { it.serverId }
32→            val removedFolderServerIds = oldFolderServerIds - newFolderServerIds
33→            deleteFolders(removedFolderServerIds)
34→        }
35→    }
36→}
